proof fn phi_4_alloc_flips_other_bits(pre: Bitmap, post: Bitmap, result: Result<usize, Error>)
    requires
        pre.inv(),
    ensures
        post.inv(),
        match result {
            Ok(index) => {
                &&& 0 <= index < post@.num_bits
                &&& post@.num_bits == pre@.num_bits
                &&& !pre@.is_bit_set(index as int)
                &&& post@.is_bit_set(index as int)
            },
            Err(_) => true,
        },
{
    // --- State assumptions ---
    assume(post.inv());
    assume(pre@.num_bits > 2);
    assume(post@.num_bits == pre@.num_bits);

    // --- Bad scenario: Ok result but some other bit changed ---
    assume(result is Ok);
    let idx = result.unwrap();
    assume(0 <= idx < post@.num_bits);
    assume(!pre@.is_bit_set(idx as int));
    assume(post@.is_bit_set(idx as int));
    assume(exists|j: int| 0 <= j < pre@.num_bits && j != idx as int && post@.is_bit_set(j) != pre@.is_bit_set(j));
}

