// Universal: no state assumptions — tests all states
proof fn phi_6_clear_already_cleared_ok(pre: Bitmap, post: Bitmap, index: usize, result: Result<(), Error>)
    requires
        pre.inv(),
    ensures
        post.inv(),
        match result {
            Ok(()) => {
                &&& index < post@.num_bits
                &&& !post@.is_bit_set(index as int)
                &&& post@.num_bits == pre@.num_bits
                &&& forall|i: int|
                    0 <= i < post@.num_bits && i != (index as int) ==> post@.is_bit_set(i)
                        == pre@.is_bit_set(i)
                &&& post@.set_bits == pre@.set_bits.remove(index as int)
                &&& post@.usage() == pre@.usage() - 1
            },
            Err(_) => {
                &&& index >= pre@.num_bits || !pre@.is_bit_set(index as int)
                &&& post@ == pre@
            },
        },
{
    // --- Bad scenario ---
    // The bit is already clear, yet clear returns Ok
    assume(!pre@.is_bit_set(index as int));
    assume(index < pre@.num_bits);
    assume(result is Ok);
}

