                    0 <= i < post@.num_bits && i != (index as int) ==> post@.is_bit_set(i)
                        == pre@.is_bit_set(i)
                &&& post@.set_bits == pre@.set_bits.remove(index as int)
                &&& post@.usage() == pre@.usage() - 1
            },
            Err(_) => {
