        number_of_bits == 0 ==> result is Err,
        number_of_bits >= u32::MAX as usize ==> result is Err,
        number_of_bits % (u8::BITS as usize) != 0 ==> result is Err,
{
    // --- State assumptions ---
    // (none — universal case, applies to all valid inputs)
    assume(number_of_bits > 0);
    assume(number_of_bits < u32::MAX as usize);
    assume(number_of_bits % (u8::BITS as usize) == 0);

    // --- Bad scenario ---
    assume(result is Err);
}

