proof fn phi_7_alloc_range_capacity_insufficient_implies_err_full(pre: Bitmap, post: Bitmap, size: usize, result: Result<usize, Error>)
    requires
        pre.inv(),
        size > 0,
        size <= pre@.num_bits,
    ensures
        post.inv(),
        match result {
            Ok(start) => {
                &&& 0 <= start < post@.num_bits
                &&& 0 < size <= post@.num_bits
                &&& start + (size as int) <= post@.num_bits
                &&& post@.num_bits == pre@.num_bits
                &&& post@.all_bits_set_in_range(start as int, start + (size as int))
                &&& pre@.all_bits_unset_in_range(
                    start as int,
                    start + (size as int),
                )
                &&& forall|i: int|
                    0 <= i < post@.num_bits && (i < start || i >= start + (size as int))
                        ==> post@.is_bit_set(i) == pre@.is_bit_set(i)
                &&& post@.set_bits == pre@.set_bits.union(
                    BitmapView::range_set(start as int, start + (size as int)),
                )
                &&& post@.usage() == pre@.usage() + (size as int)
            },
            Err(_) => {
                &&& !pre@.exists_contiguous_free_range(size as int)
                &&& post@ == pre@
            },
        },
{
    // --- State assumptions ---
    // Bitmap is completely full: usage equals num_bits
    assume(pre@.usage() == pre@.num_bits);
    assume(pre@.is_full());

    // --- Bad scenario ---
    // Despite being completely full, spec allows Ok (allocation succeeds)
    assume(result is Ok);
}

